const FUNCTION_REFERENCE = [
  ["sin / cos / tan", "Trig functions (DEG or RAD)", "sin(30) = 0.5"],
  ["sqrt", "Square root", "sqrt(144) = 12"],
  ["x^2", "Square", "7^2 = 49"],
  ["ln", "Natural log (base e)", "ln(e) = 1"],
  ["log", "Common log (base 10)", "log(1000) = 3"],
  ["n!", "Factorial", "5! = 120"],
  ["1/x", "Reciprocal", "1/4 = 0.25"],
  ["pi", "Pi constant", "3.14159265"],
  ["e", "Euler's number", "2.71828182"],
  ["^", "Exponentiation", "2^10 = 1024"],
];

type AngleMode = "deg" | "rad";

type CalcState = {
  display: string;
  memory: number;
  hasResult: boolean;
  pulse: number;
};

type CalcAction = {
  type: "press";
  key: string;
  angleMode: AngleMode;
};

type CalcButton = {
  keyValue: string;
  label?: string;
  aria?: string;
  className?: string;
};

const DIVIDE = "/";
const MULTIPLY = "x";
const MINUS = "\u2212";

const initialState: CalcState = {
  display: "0",
  memory: 0,
  hasResult: false,
  pulse: 0,
};

const operatorKeys = ["+", "-", "*", "/", "^"];
const unaryKeys = ["sin", "cos", "tan", "sqrt", "x^2", "ln", "log", "n!", "1/x", "+/-"];

const formatNumber = (value: number) => {
  if (!Number.isFinite(value)) return "Error";
  const rounded = Number(value.toFixed(10));
  return Object.is(rounded, -0) ? "0" : String(rounded);
};

const toRadians = (value: number, angleMode: AngleMode) => (
  angleMode === "deg" ? value * Math.PI / 180 : value
);

const evaluateExpression = (rawExpression: string) => {
  const trimmed = rawExpression.trim();
  if (!trimmed || trimmed === "Error") return NaN;

  const expression = trimmed
    .replace(/\bpi\b/g, `(${Math.PI})`)
    .replace(/\be\b/g, `(${Math.E})`)
    .replace(/\^/g, "**");

  if (!/^[0-9+\-*/().%\s]+$/.test(expression)) return NaN;

  try {
    const value = Function('"use strict"; return (' + expression + ')')();
    return typeof value === "number" && Number.isFinite(value) ? value : NaN;
  } catch {
    return NaN;
  }
};

const lastNumberPart = (display: string) => {
  const parts = display.split(/[+\-*/^()]/);
  return parts[parts.length - 1] ?? "";
};

const appendValue = (state: CalcState, key: string) => {
  if (state.display === "Error" || (state.hasResult && (/^\d$/.test(key) || key === "." || key === "pi" || key === "e" || key === "("))) {
    if (key === ".") return { ...state, display: "0.", hasResult: false };
    return { ...state, display: key, hasResult: false };
  }

  if (key === "." && lastNumberPart(state.display).includes(".")) return state;
  if (state.display === "0" && /^\d$/.test(key)) return { ...state, display: key, hasResult: false };
  if (state.display === "0" && (key === "pi" || key === "e" || key === "(")) return { ...state, display: key, hasResult: false };

  return { ...state, display: state.display + key, hasResult: false };
};

const applyUnaryFunction = (state: CalcState, key: string, angleMode: AngleMode) => {
  const value = evaluateExpression(state.display);
  let result = NaN;

  if (key === "sin") result = Math.sin(toRadians(value, angleMode));
  if (key === "cos") result = Math.cos(toRadians(value, angleMode));
  if (key === "tan") {
    const radians = toRadians(value, angleMode);
    result = Math.abs(Math.cos(radians)) < 1e-12 ? NaN : Math.tan(radians);
  }
  if (key === "sqrt") result = value < 0 ? NaN : Math.sqrt(value);
  if (key === "x^2") result = value * value;
  if (key === "ln") result = value > 0 ? Math.log(value) : NaN;
  if (key === "log") result = value > 0 ? Math.log10(value) : NaN;
  if (key === "n!") {
    if (Number.isInteger(value) && value >= 0 && value <= 170) {
      result = 1;
      for (let index = 2; index <= value; index += 1) result *= index;
    }
  }
  if (key === "1/x") result = value === 0 ? NaN : 1 / value;
  if (key === "+/-") result = -value;

  return {
    ...state,
    display: formatNumber(result),
    hasResult: true,
    pulse: state.pulse + 1,
  };
};

const reducer = (state: CalcState, action: CalcAction): CalcState => {
  const key = action.key;

  if (key === "C") return { ...initialState, memory: state.memory };
  if (key === "Back") {
    if (state.display === "Error" || state.hasResult) return { ...state, display: "0", hasResult: false };
    return { ...state, display: state.display.length > 1 ? state.display.slice(0, -1) : "0", hasResult: false };
  }
  if (key === "MC") return { ...state, memory: 0 };
  if (key === "MS") {
    const value = evaluateExpression(state.display);
    return Number.isFinite(value) ? { ...state, memory: value } : state;
  }
  if (key === "MR") {
    return { ...state, display: formatNumber(state.memory), hasResult: true, pulse: state.pulse + 1 };
  }
  if (key === "=" || key === "Enter") {
    return { ...state, display: formatNumber(evaluateExpression(state.display)), hasResult: true, pulse: state.pulse + 1 };
  }
  if (key === "%") {
    return { ...state, display: formatNumber(evaluateExpression(state.display) / 100), hasResult: true, pulse: state.pulse + 1 };
  }
  if (unaryKeys.includes(key)) return applyUnaryFunction(state, key, action.angleMode);
  if (operatorKeys.includes(key)) {
    if (state.display === "Error") return key === "-" ? { ...state, display: "-", hasResult: false } : state;
    const trimmed = state.display.trim();
    const last = trimmed[trimmed.length - 1];
    if (operatorKeys.includes(last) && !(key === "-" && last !== "-")) {
      return { ...state, display: trimmed.slice(0, -1) + key, hasResult: false };
    }
    return { ...state, display: trimmed + key, hasResult: false };
  }
  if (/^\d$/.test(key) || key === "." || key === "pi" || key === "e" || key === "(" || key === ")") {
    return appendValue(state, key);
  }

  return state;
};

const button = (keyValue: string, label?: string, aria?: string, className?: string): CalcButton => ({
  keyValue,
  label,
  aria,
  className,
});

